#!/usr/bin/env python3
"""FAITHFUL byte-for-byte replay of the AULA F108 Pro capture opening.

This replays the EXACT ordered sequence of Feature reports (writes) and ACK
reads the official app performed from connect through its first static color
apply, decoded from `captures/aula-f108-pro/04-connect-esc-red.pcapng`:
    connect handshake -> ~1.5s of default-effect streaming -> first static apply.

Why: an isolated static apply (tools/f108_test.py) reproduces the app's bytes,
timing, and ACKs exactly, yet the board stays dark. The one thing it skips is the
effect-streaming phase that runs once before the first static apply -- which may
implicitly power on the LED matrix. This script includes it, so if the board
lights here we know a one-time "warmup" is required and can then minimize it.

Run on native Windows with the keyboard WIRED and the AULA app CLOSED:
    pip install hid
    python tools/f108_replay.py          # ~20s; watch the board
    python tools/f108_replay.py --quiet  # less logging
The board should go through a brief rainbow-ish effect, then turn solid (the
app's captured "all red"). Tell me what you see.
"""
import sys
import time
import hid

VID, PID, IFACE = 0x0C45, 0x800A, 3
READ_LEN = 65
TICK = 0.033  # match the app's ~33 ms per-report cadence
VERBOSE = True


def open_device():
    devs = hid.enumerate(VID, PID)
    if not devs:
        sys.exit(f"No device {VID:#06x}:{PID:#06x} found. Wired? App closed?")
    chosen = next((d for d in devs if d["interface_number"] == IFACE), None) or devs[-1]
    print(f"Using: iface={chosen['interface_number']} path={chosen['path']}")
    h = hid.device()
    h.open_path(chosen["path"])
    return h


def send(h, payload):
    try:
        n = h.send_feature_report(bytes([0x00] + list(payload)))
    except Exception as e:  # noqa: BLE001
        print(f"  WRITE EXCEPTION {e!r}")
        return -1
    if n is None or n < 0:
        print(f"  write FAILED ({n}); {h.error()}")
    time.sleep(TICK)
    return n


def read(h):
    for attempt in range(3):
        try:
            data = h.get_feature_report(0, READ_LEN)
        except Exception as e:  # noqa: BLE001
            if attempt == 2:
                return b""
            time.sleep(0.004)
            continue
        time.sleep(TICK)
        return bytes(data or b"")
    return b""


