def main():
    global VERBOSE
    VERBOSE = "--quiet" not in sys.argv
    h = open_device()
    nwrite = sum(1 for o in OPS if o != "R")
    print(f"Replaying {len(OPS)} ops ({nwrite} writes) at {int(TICK*1000)}ms cadence (~{len(OPS)*TICK:.0f}s).")
    print("WATCH THE BOARD: expect a brief effect, then it should turn solid.\n")
    wi = 0
    for i, op in enumerate(OPS):
        if op == "R":
            read(h)
        else:
            wi += 1
            send(h, bytes.fromhex(op))
            if VERBOSE and (op[:4] in ("0418", "0428", "0413", "0423", "0420") or op[:2] == "80"):
                print(f"  [{i}] cmd {op[:4]}")
            elif wi % 50 == 0:
                print(f"  ... {wi}/{nwrite} writes")
    h.close()
    print("\nDone. Did the board light (effect and/or solid)? What color did it end on?")


if __name__ == "__main__":
    main()
